const cbq = $input.first().json.callback_query;
const [, orderId, newStatus] = cbq.data.split(':');
return [{ json: {
  orderId,
  newStatus,
  chatId: String(cbq.message.chat.id),
  callbackId: cbq.id,
  messageId: cbq.message.message_id
} }];

const msg = $input.first().json.message;
const text = (msg?.text || '').trim();
const parts = text.split(/\s+/);
const cmd = parts[0]?.toLowerCase() || '';
const arg = parts.slice(1).join(' ').trim();
const chatId = String(msg.chat.id);
let type = 'help';
if (cmd === '/orders' || cmd === '/طلبات') type = 'orders';
else if (cmd === '/summary' || cmd === '/ملخص') type = 'summary';
else if ((cmd === '/customer' || cmd === '/عميل') && arg) type = 'customer';
return [{ json: { type, arg, chatId } }];

const orders = $input.first().json;
const chatId = $('Parse Command').item.json.chatId;
const statusAr = { pending: '⏳ انتظار', preparing: '👨‍🍳 تحضير', on_the_way: '🛵 في الطريق', delivered: '✅ تم', cancelled: '🚫 ملغي' };
if (!orders.length) return [{ json: { chatId, text: 'لا توجد طلبات.' } }];
const lines = orders.slice(0, 10).map(o => {
  const items = (Array.isArray(o.items) ? o.items : JSON.parse(o.items)).map(i => `${i.name} ×${i.quantity}`).join('، ');
  return `*#${o.order_number}* — ${o.customer_name}\n📞 ${o.phone} | ${o.total} ج.م | ${statusAr[o.status] || o.status}\n${items}`;
}).join('\n\n');
const filterLabel = $('Parse Command').item.json.arg ? ` (${statusAr[$('Parse Command').item.json.arg] || $('Parse Command').item.json.arg})` : '';
return [{ json: { chatId, text: `📋 *آخر الطلبات${filterLabel}*\n\n${lines}` } }];

const orders = $input.first().json;
const chatId = $('Parse Command').item.json.chatId;
const statusAr = { pending: '⏳ قيد الانتظار', preparing: '👨‍🍳 جاري التحضير', on_the_way: '🛵 في الطريق', delivered: '✅ تم التوصيل', cancelled: '🚫 ملغي' };
const total = orders.reduce((s, o) => s + Number(o.total), 0);
const byStatus = {};
orders.forEach(o => { if (!byStatus[o.status]) byStatus[o.status] = { count: 0, total: 0 }; byStatus[o.status].count++; byStatus[o.status].total += Number(o.total); });
const lines = Object.entries(byStatus).map(([s, v]) => `${statusAr[s] || s}: *${v.count}* طلب — *${v.total}* ج.م`).join('\n');
const text = `📊 *ملخص الطلبات*\n\n${lines}\n\n💰 *الإجمالي الكلي: ${total.toLocaleString()} ج.م*\n📦 *عدد الطلبات: ${orders.length}*`;
return [{ json: { chatId, text } }];

const data = $input.first().json;
const chatId = $('Parse Command').item.json.chatId;
if (data.error) return [{ json: { chatId, text: '❌ العميل مش موجود. تأكد من رقم التليفون.' } }];
const statusAr = { pending: '⏳', preparing: '👨‍🍳', on_the_way: '🛵', delivered: '✅', cancelled: '🚫' };
const orders = data.orders || [];
const totalSpent = orders.reduce((s, o) => s + Number(o.total), 0);
const orderLines = orders.slice(0, 5).map(o => {
  const items = (Array.isArray(o.items) ? o.items : JSON.parse(o.items)).map(i => `${i.name} ×${i.quantity}`).join('، ');
  return `${statusAr[o.status] || ''} *#${o.order_number}* — ${o.total} ج.م\n${items}`;
}).join('\n\n');
const text = [
  `👤 *${data.name}*`,
  `📞 ${data.phone}`,
  data.address ? `📍 ${data.address}` : '',
  '',
  `📦 عدد الطلبات: *${orders.length}*`,
  `💰 إجمالي الإنفاق: *${totalSpent} ج.م*`,
  orders.length ? `\n*آخر الطلبات:*\n\n${orderLines}` : ''
].filter(Boolean).join('\n');
return [{ json: { chatId, text } }];
